import React, { useState } from "react";

const ContactUs = () => {

  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    email: "",
    message: ""
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    console.log(formData);

    alert("Message sent successfully!");

    setFormData({
      name: "",
      phone: "",
      email: "",
      message: ""
    });
  };

  return (

    <div className="pageCntsContainer">

      <span className="PageHeader">Contact Us</span>

      {/* Contact Banner */}

      <div style={{textAlign:"center", marginBottom:"20px"}}>
        <img
          src="/images/Common/contactus.png"
          alt="Contact Us"
          style={{maxWidth:"100%"}}
        />
      </div>

      {/* Contact Details */}

      <div style={{display:"flex", justifyContent:"center"}}>

        <table cellPadding="8" cellSpacing="0">

          <tbody>

            <tr>
              <td className="ContUsLabel">Company Name :</td>
              <td className="ContUsCompanyName">
                SUN EMIRATES MECHANICAL WORKS LLC
              </td>
            </tr>

            <tr>
              <td className="ContUsLabel">Address :</td>
              <td className="ContUsAddress">
                P.O.Box : 14655, Ajman - U.A.E.
              </td>
            </tr>

            <tr>
              <td className="ContUsLabel">Telephone :</td>
              <td className="ContUsTelNo">
                +971-6-7481646
              </td>
            </tr>

            <tr>
              <td className="ContUsLabel">Fax :</td>
              <td className="ContUsFaxNo">
                +971-6-7481647
              </td>
            </tr>

            <tr>
              <td className="ContUsLabel">Mobile :</td>
              <td className="ContUsMobileNo">
                +971-50-7743556
              </td>
            </tr>

            <tr>
              <td className="ContUsLabel">Email :</td>
              <td className="ContUsEMailId">
                <a href="mailto:sales@sunemirates.com">sales@sunemirates.com</a><br/>
                <a href="mailto:saminathan@sunemirates.com">saminathan@sunemirates.com</a><br/>
                <a href="mailto:sunemw@eim.ae">sunemw@eim.ae</a>
              </td>
            </tr>

          </tbody>

        </table>

      </div>

      {/* Contact Form */}

      <div style={{display:"flex", justifyContent:"center", marginTop:"30px"}}>

        <form onSubmit={handleSubmit} style={{width:"350px"}}>

          <input
            type="text"
            name="name"
            placeholder="Your Name"
            value={formData.name}
            onChange={handleChange}
            required
            style={{width:"100%",padding:"8px",marginBottom:"10px"}}
          />

          <input
            type="text"
            name="phone"
            placeholder="Phone Number"
            value={formData.phone}
            onChange={handleChange}
            required
            style={{width:"100%",padding:"8px",marginBottom:"10px"}}
          />

          <input
            type="email"
            name="email"
            placeholder="Email"
            value={formData.email}
            onChange={handleChange}
            required
            style={{width:"100%",padding:"8px",marginBottom:"10px"}}
          />

          <textarea
            name="message"
            placeholder="Message"
            rows="4"
            value={formData.message}
            onChange={handleChange}
            required
            style={{width:"100%",padding:"8px",marginBottom:"10px"}}
          />

          <button className="btnSubmit" type="submit">
            Send Message
          </button>

        </form>

      </div>

      {/* Google Map */}

      <div style={{marginTop:"40px", textAlign:"center"}}>

        <h3>Our Location</h3>

        <iframe
          title="Sun Emirates Map"
          src="https://maps.google.com/maps?q=Ajman%20UAE&t=&z=13&ie=UTF8&iwloc=&output=embed"
          width="80%"
          height="350"
          style={{border:"0"}}
        ></iframe>

      </div>

    </div>

  );
};

export default ContactUs;
